void save_registers(uint64_t* regs) {
    // 使用内联汇编将寄存器的值保存到对应的数组元素中
    __asm {
        mov [regs + 0], eax ; 保存 EAX 的值到 regs[0]
        mov [regs + 8], ecx ; 保存 ECX 的值到 regs[1]
        mov [regs + 16], edx ; 保存 EDX 的值到 regs[2]
        mov [regs + 24], esp ; 保存 ESP 的值到 regs[3]
        mov [regs + 32], ebp ; 保存 EBP 的值到 regs[4]
    }
